import React from 'react';

const Features = () => (
    <section style={{ padding: '80px 20px', background: '#0c0a09' }}>
        <div style={{ maxWidth: '1000px', margin: '0 auto', display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '40px' }}>
            {[1, 2, 3].map(i => (
                <div key={i} style={{ textAlign: 'center', padding: '30px', background: '#171717', borderRadius: '24px' }}>
                    <div style={{ width: '60px', height: '60px', background: '#2563eb', margin: '0 auto 20px', borderRadius: '16px', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff' }}>{i}</div>
                    <h4 style={{ color: '#fff' }}>Langkah {i}</h4>
                    <p style={{ color: '#737373', fontSize: '14px' }}>Deskripsi singkat cara kerja aplikasi kami.</p>
                </div>
            ))}
        </div>
    </section>
);
export default Features;
